import { useEffect, useRef, useState } from "react";

/**
 * useDeviceInfo
 * - Detects platform (iOS, Android, Chrome, Safari, etc.) on mount.
 * - Tracks mobile keyboard open state via visualViewport / resize events.
 *
 * Returns: { deviceInfo, isKeyboardOpen }
 *
 * Extracted from Siri.js as part of Phase 3 cleanup. Logic is unchanged
 * from the inline version — same UA regexes, same keyboard threshold.
 */
export default function useDeviceInfo() {
  const [deviceInfo, setDeviceInfo] = useState({});
  const [isKeyboardOpen, setIsKeyboardOpen] = useState(false);
  const initialViewportHeight = useRef(
    typeof window !== "undefined" ? window.innerHeight : 0
  );

  useEffect(() => {
    if (typeof window === "undefined" || typeof navigator === "undefined") {
      return undefined;
    }

    const userAgent = (navigator.userAgent || "").toLowerCase();
    const platform = (navigator.platform || "").toLowerCase();

    const info = {
      isMobile: /android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini/i.test(
        userAgent
      ),
      isIOS:
        /ipad|iphone|ipod/.test(userAgent) ||
        (platform === "macintel" && navigator.maxTouchPoints > 1),
      isAndroid: /android/i.test(userAgent),
      isChrome: /chrome/i.test(userAgent) && !/edge/i.test(userAgent),
      isFirefox: /firefox/i.test(userAgent),
      isSafari: /safari/i.test(userAgent) && !/chrome/i.test(userAgent),
      isEdge: /edge/i.test(userAgent),
      hasTouch: "ontouchstart" in window || navigator.maxTouchPoints > 0,
      isStandalone:
        window.navigator.standalone === true ||
        window.matchMedia("(display-mode: standalone)").matches,
      supports3D: CSS.supports("transform-style", "preserve-3d"),
      supportsBackdropFilter: CSS.supports("backdrop-filter", "blur(10px)"),
      hasHardwareAcceleration: !!window.DeviceOrientationEvent,
      screenSize: {
        width: window.screen.width,
        height: window.screen.height,
        ratio: window.devicePixelRatio || 1,
      },
    };

    setDeviceInfo(info);

    if (!info.isMobile) {
      return undefined;
    }

    // Mobile-only listeners below
    const cleanups = [];

    if (info.isIOS) {
      const viewport = document.querySelector('meta[name="viewport"]');
      if (viewport) {
        viewport.setAttribute(
          "content",
          "width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no, viewport-fit=cover"
        );
      }

      if (window.visualViewport) {
        const handleIOSResize = () => {
          const currentHeight = window.visualViewport.height;
          const heightDifference =
            initialViewportHeight.current - currentHeight;
          setIsKeyboardOpen(heightDifference > 150);
        };
        window.visualViewport.addEventListener("resize", handleIOSResize);
        cleanups.push(() =>
          window.visualViewport.removeEventListener("resize", handleIOSResize)
        );
      }
    }

    const handleResize = () => {
      const heightDifference =
        initialViewportHeight.current - window.innerHeight;
      setIsKeyboardOpen(heightDifference > 150);
    };
    const handleOrientationChange = () => {
      setTimeout(() => {
        initialViewportHeight.current = window.innerHeight;
        setIsKeyboardOpen(false);
      }, 500);
    };

    window.addEventListener("resize", handleResize);
    window.addEventListener("orientationchange", handleOrientationChange);
    cleanups.push(() => {
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("orientationchange", handleOrientationChange);
    });

    return () => cleanups.forEach((c) => c());
  }, []);

  return { deviceInfo, isKeyboardOpen };
}
