// Streams text into the transcript with a typing caret. Scroll is kept
// pinned to the bottom by the parent effect via onTick.
const TypewriterText = ({ text, instant, onTick }) => {
  const [count, setCount] = useState(instant ? text.length : 0);

  useEffect(() => {
    if (instant) {
      setCount(text.length);
      return undefined;
    }
    setCount(0);
    if (!text) return undefined;
    // Scale the step so long answers finish in ~3-4s instead of crawling
    const step = Math.max(1, Math.ceil(text.length / 140));
    const interval = setInterval(() => {
      setCount((c) => {
        const next = Math.min(text.length, c + step);
        if (next >= text.length) clearInterval(interval);
        return next;
      });
    }, 26);
    return () => clearInterval(interval);
  }, [text, instant]);

  useEffect(() => {
    if (onTick) onTick();
  }, [count, onTick]);

  return (
    <>
      {text.slice(0, count)}
      {count < text.length && <span className="type-caret" />}
    </>
  );
};

